        temp = strrep(xvar{jj},'/','By');
    else
        temp = xvar{jj};
    end
    newstr{jj} = [upper(temp(1))  temp(2:end)];
end
xparam = [newstr{:}];

ystr = strsplit(info.Yaxis,' (');
