newstr = cell(length(yvar),1);
for jj = 1:length(yvar)
    if contains(yvar{jj},'/')
        temp = strrep(yvar{jj},'/','By');
    else
        temp = yvar{jj};
    end
    newstr{jj} = [upper(temp(1))  temp(2:end)];
end
yparam = [newstr{:}];

for ii = 1:length(res)
    a = info.Xvalues{ii};
    nData = 5;
    b = (a(2)-a(1))/(nData-1);
    c =  a(1)+(0:nData-1)*b;
    vectorSpecValue = c;
    xVec = zeros(nData,1);
    yVec = zeros(nData,1);
    for  kk = 1 : length(vectorSpecValue)
        if strcmp(xspec,'res')
            eval([xspec '(ii).' xparam '= vectorSpecValue(kk);']);
        else
            eval([xspec '{ii}.' xparam '= vectorSpecValue(kk);']);
        end
        if strcmp(info.Xtype,'Results')
            resCustom = calculateLinkBudget(spec{ii},sat{ii},tx{ii},rx{ii},lnk{ii},...
                yvar,xparam,res(ii).(xparam));
        else
            resCustom = calculateLinkBudget(spec{ii},sat{ii},tx{ii},rx{ii},lnk{ii},yvar);
        end
        yVec(kk) = resCustom.(yparam);
        xVec(kk) = vectorSpecValue(kk);
    end
    xCurrentValue(ii) =  xVec(3);
